    assertEquals(directAsString, throughNode);


    mapper = JsonMapper.builder().build();

    directAsString = mapper.writeValueAsString(bigDecimal);
    throughNode = mapper.writeValueAsString(mapper.valueToTree(bigDecimal));
    assertEquals(directAsString, throughNode);
``` 


